import collections
import json
import boto3
from botocore import UNSIGNED
from botocore.config import Config

source = 'datagov/traffic-counts-fc3cd/files/data.txt'
bucket = "lakeqa-yc4103-datalake"
obj = boto3.client("s3", config=Config(signature_version=UNSIGNED)).get_object(Bucket=bucket, Key=source)
geo = json.loads(obj["Body"].read().decode("utf-8", errors="replace"))

values = collections.defaultdict(list)
for feature in geo.get("features", []):
    props = feature.get("properties", {}) or {}
    for year in range(2011, 2017):
        value = props.get(f"Y{year}")
        if value is not None:
            try:
                values[year].append(float(value))
            except (TypeError, ValueError):
                pass
yearly_averages = {year: sum(vals) / len(vals) for year, vals in values.items() if vals}
answer = str(min(yearly_averages, key=lambda year: (yearly_averages[year], year)))
